// Recipient is set on the email node itself (node config, not msg.to).
const rows = msg.payload || [];
const nowDate = new Date();

// Determine which 12h period this report covers based on Helsinki hour.
// Inject fires at 08:00 (covers 20:00-08:00) or 20:00 (covers 08:00-20:00).
const etHour = parseInt(nowDate.toLocaleString('fi-FI', {timeZone: 'Europe/Helsinki', hour: 'numeric', hour12: false}));
const isEvening = etHour >= 14;
const periodLabel = isEvening ? '08:00 - 20:00' : '20:00 - 08:00';
const dateLabel = nowDate.toLocaleDateString('fi-FI', {timeZone: 'Europe/Helsinki'});
const now = nowDate.toLocaleString('fi-FI', {timeZone: 'Europe/Helsinki'});

const fmt = v => typeof v === 'number' ? v.toFixed(2) : '-';

// Group rows by gateway_id → location → device_id
const byGateway = {};
for (const r of rows) {
    const gw  = r.gateway_id || 'unknown';
    const loc = r.location   || 'unknown';
    const dev = r.device_id  || 'unknown';
    if (!byGateway[gw]) byGateway[gw] = {};
    if (!byGateway[gw][loc]) byGateway[gw][loc] = {};
    if (!byGateway[gw][loc][dev]) byGateway[gw][loc][dev] = [];
    byGateway[gw][loc][dev].push(r);
}

let html = '<h2 style="font-family:sans-serif">IoT Sensor Report</h2>';
html += '<p style="font-family:sans-serif;color:#555">Period: <strong>' + periodLabel + '</strong> &nbsp;|&nbsp; ' + dateLabel + '</p>';
html += '<p style="font-family:sans-serif;color:#999;font-size:12px">Generated: ' + now + '</p>';

if (rows.length === 0) {
    html += '<p style="font-family:sans-serif;color:#c00"><strong>No data received in this period.</strong></p>';
} else {
    for (const [gw, locations] of Object.entries(byGateway)) {
        html += '<h3 style="font-family:sans-serif;color:#333">' + gw + '</h3>';
        for (const [loc, devices] of Object.entries(locations)) {
            html += '<h4 style="font-family:sans-serif;color:#555;margin-left:16px">' + loc + '</h4>';
            for (const [device, readings] of Object.entries(devices)) {
                html += '<p style="font-family:sans-serif;margin-left:32px"><strong>' + device + '</strong></p>';
                html += '<table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse;font-family:sans-serif;font-size:14px;margin-left:32px">';
                html += '<tr style="background:#f0f0f0"><th>Measurement</th><th>Min</th><th>Max</th><th>Current</th><th>Unit</th><th>Last reading</th></tr>';
                for (const r of readings) {
                    const lastTime = r.lastTime ? new Date(r.lastTime).toLocaleString('fi-FI', {timeZone: 'Europe/Helsinki'}) : '-';
                    html += '<tr>';
                    html += '<td>' + (r.measurement_type || '-') + '</td>';
                    html += '<td>' + fmt(r.min) + '</td>';
                    html += '<td>' + fmt(r.max) + '</td>';
                    html += '<td><strong>' + fmt(r.current) + '</strong></td>';
                    html += '<td>' + (r.unit || '-') + '</td>';
                    html += '<td>' + lastTime + '</td>';
                    html += '</tr>';
                }
                html += '</table><br>';
            }
        }
    }
}

msg.topic = 'IoT Report ' + periodLabel + ' - ' + dateLabel;
msg.payload = html;
return msg;

// Recipient is set on the email node itself (node config, not msg.to).
// 4-hour cooldown between repeated alerts.
const ALERT_COOLDOWN_HOURS = 4;

const rows = msg.payload || [];
const total = rows.reduce((s, r) => s + (r._value || 0), 0);

if (total > 0) {
    // Data is flowing — clear alert state so next outage fires fresh
    flow.set('alertSent', false);
    return null;
}

// No data in last 1 hour — check cooldown
const lastSent = flow.get('lastAlertSent') || 0;
const hoursSince = (Date.now() - lastSent) / 3600000;

if (hoursSince < ALERT_COOLDOWN_HOURS) {
    return null;  // suppress: already alerted recently
}

flow.set('lastAlertSent', Date.now());
flow.set('alertSent', true);

const sinceWhen = new Date(Date.now() - 3600000).toLocaleString('fi-FI', { timeZone: 'Europe/Helsinki' });
msg.topic = '⚠️ IoT Alert — No sensor data for 1+ hour';
msg.payload = `No sensor measurements have been received since ${sinceWhen} (EET).\n\nPlease check the gateway and sensor node.`;
return msg;
